x = 0.5 +(gmegabuf(index)-0.5)/q2;
y = 0.5 + (gmegabuf(index+1)-0.5)/q2;

// collecting pairs of index and distance to the current object in a local buffer
i = 0;
j = 0; 
loop(q31,
     d = sqrt( sqr(gmegabuf(index)-gmegabuf(i)) + sqr(gmegabuf(index+1)-gmegabuf(i+1)));
     d = if( equal(d,0), 1, d);
     megabuf(j)   = i; // store index/distance pairs
     megabuf(j+1) = d; 
     j = j+2;
     i = i+q32;
    );

// sort that buffer, but only 5 cycles for the 5 nearest objects
i = 0;
loop( 5,
      j = i;
      smallestfind = 100;
      findindex = 0;
      loop( q31-j,
            distance =megabuf(j*2+1);
            smaller = above( smallestfind, distance);
            smallestfind = if(smaller, distance, smallestfind);
            findindex = if( smaller, j*2, findindex);
            j = j + 1;
          );

      // now that the nearest object was found, swap it to the buffer's top

      j = megabuf(i);
      d = megabuf(i+1);

      megabuf(i)   = megabuf(findindex);
      megabuf(i+1) = megabuf(findindex+1);
      megabuf(findindex)   = j;
      megabuf(findindex+1) = d;

      i = i+1;
    );


